theme.custom_css:
/* ── Dark navy logo in light mode ── */
body.light-mode #site-nav-logo{filter:brightness(0) invert(1) sepia(1) saturate(5000%) hue-rotate(160deg) brightness(0.22) saturate(0.47)!important;opacity:1!important;}
/* ── Pure black nav links in light mode ── */
body.light-mode #nav ul li a{color:#000000!important;}
body.light-mode #nav ul li a:hover{color:#007AFF!important;}
/* ── Tekst in blauwe knoppen blijft altijd wit (hogere specificiteit wint van .text-white) ── */
body.light-mode .btn-primary.text-white,
body.light-mode .text-white.btn-primary,
body.light-mode .btn-primary,
body.light-mode .btn-primary *,
body.light-mode a.btn-primary,
body.light-mode button.btn-primary{color:#ffffff!important;}
